{"content": "     1|/**
     2| * Automaton Tool System
     3| *
     4| * Defines all tools the automaton can call, with self-preservation guards.
     5| * Tools are organized by category and exposed to the inference model.
     6| */
     7|
     8|import nodePath from "node:path";
     9|import { ulid } from "ulid";
    10|import type {
    11|  AutomatonTool,
    12|  ToolContext,
    13|  ToolCategory,
    14|  InferenceToolDefinition,
    15|  ToolCallResult,
    16|  GenesisConfig,
    17|  RiskLevel,
    18|  PolicyRequest,
    19|  InputSource,
    20|  SpendTrackerInterface,
    21|} from "../types.js";
    22|import type { PolicyEngine } from "./policy-engine.js";
    23|import { sanitizeToolResult, sanitizeInput } from "./injection-defense.js";
    24|import { createLogger } from "../observability/logger.js";
    25|
    26|const logger = createLogger("tools");
    27|
    28|// ‚îÄ‚îÄ‚îÄ Path Confinement ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
    29|// write_file is restricted to the sandbox home directory tree.
    30|// The sandbox home is /root for both local and remote execution.
    31|const SANDBOX_HOME = "/root";
    32|
    33|/**
    34| * Validate that a file path resolves to within the allowed root directory.
    35| * Returns the resolved absolute path, or an error string if out of bounds.
    36| */
    37|function confinePathToSandbox(filePath: string): string | { error: string } {
    38|  // Resolve ~ to SANDBOX_HOME
    39|  const expanded = filePath.startsWith("~")
    40|    ? nodePath.join(SANDBOX_HOME, filePath.slice(1))
    41|    : filePath;
    42|  // Resolve to absolute (relative paths resolve against SANDBOX_HOME)
    43|  const resolved = nodePath.resolve(SANDBOX_HOME, expanded);
    44|  // Ensure the resolved path is within the sandbox home
    45|  if (resolved !== SANDBOX_HOME && !resolved.startsWith(SANDBOX_HOME + "/")) {
    46|    return {
    47|      error: `Blocked: write_file path "${filePath}" resolves to "${resolved}" which is outside the allowed directory (${SANDBOX_HOME}). Writes are confined to the sandbox home.`,
    48|    };
    49|  }
    50|  return resolved;
    51|}
    52|
    53|// Tools whose results come from external sources and need sanitization
    54|const EXTERNAL_SOURCE_TOOLS = new Set([
    55|  "exec",
    56|  "web_fetch",
    57|  "check_social_inbox",
    58|]);
    59|
    60|// ‚îÄ‚îÄ‚îÄ Self-Preservation Guard ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
    61|// Defense-in-depth: policy engine (command.forbidden_patterns rule) is the primary guard.
    62|// This inline check is kept as a secondary safety net in case the policy engine is bypassed.
    63|
    64|const FORBIDDEN_COMMAND_PATTERNS = [
    65|  // Self-destruction
    66|  /rm\s+(-rf?\s+)?.*\.automaton/,
    67|  /rm\s+(-rf?\s+)?.*state\.db/,
    68|  /rm\s+(-rf?\s+)?.*wallet\.json/,
    69|  /rm\s+(-rf?\s+)?.*automaton\.json/,
    70|  /rm\s+(-rf?\s+)?.*heartbeat\.yml/,
    71|  /rm\s+(-rf?\s+)?.*SOUL\.md/,
    72|  // Process killing
    73|  /kill\s+.*automaton/,
    74|  /pkill\s+.*automaton/,
    75|  /systemctl\s+(stop|disable)\s+automaton/,
    76|  // Database destruction
    77|  /DROP\s+TABLE/i,
    78|  /DELETE\s+FROM\s+(turns|identity|kv|schema_version|skills|children|registry)/i,
    79|  /TRUNCATE/i,
    80|  // Safety infrastructure modification via shell
    81|  /sed\s+.*injection-defense/,
    82|  /sed\s+.*self-mod\/code/,
    83|  /sed\s+.*audit-log/,
    84|  />\s*.*injection-defense/,
    85|  />\s*.*self-mod\/code/,
    86|  />\s*.*audit-log/,
    87|  // Credential harvesting
    88|  /cat\s+.*\.ssh/,
    89|  /cat\s+.*\.gnupg/,
    90|  /cat\s+.*\.env/,
    91|  /cat\s+.*wallet\.json/,
    92|];
    93|
    94|function isForbiddenCommand(command: string, sandboxId: string): string | null {
    95|  for (const pattern of FORBIDDEN_COMMAND_PATTERNS) {
    96|    if (pattern.test(command)) {
    97|      return `Blocked: Command matches self-harm pattern: ${pattern.source}`;
    98|    }
    99|  }
   100|
   101|  // Block deleting own sandbox
   102|  if (command.includes("sandbox_delete") && command.includes(sandboxId)) {
   103|    return "Blocked: Cannot delete own sandbox";
   104|  }
   105|
   106|  return null;
   107|}
   108|
   109|// ‚îÄ‚îÄ‚îÄ Built-in Tools ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
   110|
   111|export function createBuiltinTools(sandboxId: string): AutomatonTool[] {
   112|  return [
   113|    // ‚îÄ‚îÄ VM/Sandbox Tools ‚îÄ‚îÄ
   114|    {
   115|      name: "exec",
   116|      description:
   117|        "Execute a shell command in your sandbox. Returns stdout, stderr, and exit code.",
   118|      category: "vm",
   119|      riskLevel: "caution",
   120|      parameters: {
   121|        type: "object",
   122|        properties: {
   123|          command: {
   124|            type: "string",
   125|            description: "The shell command to execute",
   126|          },
   127|          timeout: {
   128|            type: "number",
   129|            description: "Timeout in milliseconds (default: 30000)",
   130|          },
   131|        },
   132|        required: ["command"],
   133|      },
   134|      execute: async (args, ctx) => {
   135|        const command = args.command as string;
   136|        const forbidden = isForbiddenCommand(command, ctx.identity.sandboxId);
   137|        if (forbidden) return forbidden;
   138|
   139|        const result = await ctx.conway.exec(
   140|          command,
   141|          (args.timeout as number) || 30000,
   142|        );
   143|        return `exit_code: ${result.exitCode}\nstdout: ${result.stdout}\nstderr: ${result.stderr}`;
   144|      },
   145|    },
   146|    {
   147|      name: "write_file",
   148|      description: "Write content to a file in your sandbox.",
   149|      category: "vm",
   150|      riskLevel: "caution",
   151|      parameters: {
   152|        type: "object",
   153|        properties: {
   154|          path: { type: "string", description: "File path" },
   155|          content: { type: "string", description: "File content" },
   156|        },
   157|        required: ["path", "content"],
   158|      },
   159|      execute: async (args, ctx) => {
   160|        const filePath = args.path as string;
   161|        // Path confinement: restrict writes to sandbox home directory
   162|        const confined = confinePathToSandbox(filePath);
   163|        if (typeof confined === "object") return confined.error;
   164|        // Guard against overwriting protected files (same check as edit_own_file)
   165|        const { isProtectedFile } = await import("../self-mod/code.js");
   166|        if (isProtectedFile(confined)) {
   167|          return "Blocked: Cannot overwrite protected file. This is a hard-coded safety invariant.";
   168|        }
   169|        await ctx.conway.writeFile(confined, args.content as string);
   170|        return `File written: ${confined}`;
   171|      },
   172|    },
   173|    {
   174|      name: "read_file",
   175|      description: "Read content from a file in your sandbox.",
   176|      category: "vm",
   177|      riskLevel: "safe",
   178|      parameters: {
   179|        type: "object",
   180|        properties: {
   181|          path: { type: "string", description: "File path to read" },
   182|        },
   183|        required: ["path"],
   184|      },
   185|      execute: async (args, ctx) => {
   186|        const filePath = args.path as string;
   187|        // Block reads of sensitive files (wallet, env, config secrets)
   188|        const basename = filePath.split("/").pop() || "";
   189|        const sensitiveFiles = ["wallet.json", ".env", "automaton.json"];
   190|        const sensitiveExtensions = [".key", ".pem"];
   191|        if (
   192|          sensitiveFiles.includes(basename) ||
   193|          sensitiveExtensions.some((ext) => basename.endsWith(ext)) ||
   194|          basename.startsWith("private-key")
   195|        ) {
   196|          return "Blocked: Cannot read sensitive file. This protects credentials and secrets.";
   197|        }
   198|        try {
   199|          return await ctx.conway.readFile(filePath);
   200|        } catch {
   201|          // Conway files/read API may be broken ‚Äî fall back to exec(cat)
   202|          const result = await ctx.conway.exec(
   203|            `cat ${escapeShellArg(filePath)}`,
   204|            30_000,
   205|          );
   206|          if (result.exitCode !== 0) {
   207|            return `ERROR: File not found or not readable: ${filePath}`;
   208|          }
   209|          return result.stdout;
   210|        }
   211|      },
   212|    },
   213|    {
   214|      name: "expose_port",
   215|      description:
   216|        "Expose a port from your sandbox to the internet. Returns a public URL.",
   217|      category: "vm",
   218|      riskLevel: "caution",
   219|      parameters: {
   220|        type: "object",
   221|        properties: {
   222|          port: { type: "number", description: "Port number to expose" },
   223|        },
   224|        required: ["port"],
   225|      },
   226|      execute: async (args, ctx) => {
   227|        const info = await ctx.conway.exposePort(args.port as number);
   228|        return `Port ${info.port} exposed at: ${info.publicUrl}`;
   229|      },
   230|    },
   231|    {
   232|      name: "remove_port",
   233|      description: "Remove a previously exposed port.",
   234|      category: "vm",
   235|      riskLevel: "caution",
   236|      parameters: {
   237|        type: "object",
   238|        properties: {
   239|          port: { type: "number", description: "Port number to remove" },
   240|        },
   241|        required: ["port"],
   242|      },
   243|      execute: async (args, ctx) => {
   244|        await ctx.conway.removePort(args.port as number);
   245|        return `Port ${args.port} removed`;
   246|      },
   247|    },
   248|
   249|    // ‚îÄ‚îÄ Conway API Tools ‚îÄ‚îÄ
   250|    {
   251|      name: "check_credits",
   252|      description: "Check your current Conway compute credit balance.",
   253|      category: "conway",
   254|      riskLevel: "safe",
   255|      parameters: { type: "object", properties: {} },
   256|      execute: async (_args, ctx) => {
   257|        const balance = await ctx.conway.getCreditsBalance();
   258|        return `Credit balance: $${(balance / 100).toFixed(2)} (${balance} cents)`;
   259|      },
   260|    },
   261|    {
   262|      name: "check_usdc_balance",
   263|      description: "Check your on-chain USDC balance.",
   264|      category: "conway",
   265|      riskLevel: "safe",
   266|      parameters: { type: "object", properties: {} },
   267|      execute: async (_args, ctx) => {
   268|        const { getUsdcBalance } = await import("../conway/x402.js");
   269|        const chainType = ctx.config.chainType || ctx.identity.chainType || "evm";
   270|        const network = chainType === "solana" ? "solana:mainnet" : "eip155:8453";
   271|        const balance = await getUsdcBalance(ctx.identity.address, network, chainType);
   272|        const networkLabel = chainType === "solana" ? "Solana" : "Base";
   273|        return `USDC balance: ${balance.toFixed(6)} USDC on ${networkLabel}`;
   274|      },
   275|    },
   276|    {
   277|      name: "topup_credits",
   278|      description:
   279|        "Buy Conway compute credits by paying USDC from your wallet via x402. Valid tier amounts: $5, $25, $100, $500, $1000, $2500. Check your USDC balance first with check_usdc_balance.",
   280|      category: "financial",
   281|      riskLevel: "caution",
   282|      parameters: {
   283|        type: "object",
   284|        properties: {
   285|          amount_usd: {
   286|            type: "number",
   287|            description:
   288|              "Amount in USD to spend on credits. Must be one of the valid tiers: 5, 25, 100, 500, 1000, 2500.",
   289|          },
   290|        },
   291|        required: ["amount_usd"],
   292|      },
   293|      execute: async (args, ctx) => {
   294|        // Solana guard: x402 topup is EVM-only
   295|        const chainType = ctx.config.chainType || ctx.identity.chainType || "evm";
   296|        if (chainType === "solana") {
   297|          return "Credit topup via x402 requires an EVM wallet. Solana automatons should fund credits via the Conway dashboard or credits API.";
   298|        }
   299|
   300|        const { topupCredits, TOPUP_TIERS } =
   301|          await import("../conway/topup.js");
   302|        const amountUsd = args.amount_usd as number;
   303|
   304|        if (!TOPUP_TIERS.includes(amountUsd)) {
   305|          return `Invalid tier. Valid amounts (USD): ${TOPUP_TIERS.join(", ")}`;
   306|        }
   307|
   308|        // Check USDC balance first (EVM-only path after Solana guard above)
   309|        const { getUsdcBalance } = await import("../conway/x402.js");
   310|        const usdcBalance = await getUsdcBalance(ctx.identity.address, "eip155:8453");
   311|        if (usdcBalance < amountUsd) {
   312|          return `Insufficient USDC. Balance: $${usdcBalance.toFixed(2)}, requested: $${amountUsd}. Choose a smaller tier or wait for funding.`;
   313|        }
   314|
   315|        const result = await topupCredits(
   316|          ctx.config.conwayApiUrl,
   317|          ctx.identity.account,
   318|          amountUsd,
   319|        );
   320|
   321|        if (!result.success) {
   322|          return `Credit topup failed: ${result.error}`;
   323|        }
   324|
   325|        // Record transaction
   326|        const { ulid } = await import("ulid");
   327|        ctx.db.insertTransaction({
   328|          id: ulid(),
   329|          type: "credit_purchase",
   330|          amountCents: amountUsd * 100,
   331|          balanceAfterCents: result.creditsCentsAdded,
   332|          description: `x402 credit topup: $${amountUsd} USD`,
   333|          timestamp: new Date().toISOString(),
   334|        });
   335|
   336|        return `Credit topup successful: +$${amountUsd} (${amountUsd * 100} cents) credits purchased via x402. Check your new balance with check_credits.`;
   337|      },
   338|    },
   339|    {
   340|      name: "create_sandbox",
   341|      description:
   342|        "Create a new Conway sandbox (separate VM) for sub-tasks or testing.",
   343|      category: "conway",
   344|      riskLevel: "caution",
   345|      parameters: {
   346|        type: "object",
   347|        properties: {
   348|          name: { type: "string", description: "Sandbox name" },
   349|          vcpu: { type: "number", description: "vCPUs (default: 1)" },
   350|          memory_mb: {
   351|            type: "number",
   352|            description: "Memory in MB (default: 512)",
   353|          },
   354|          disk_gb: {
   355|            type: "number",
   356|            description: "Disk in GB (default: 5)",
   357|          },
   358|        },
   359|      },
   360|      execute: async (args, ctx) => {
   361|        const info = await ctx.conway.createSandbox({
   362|          name: args.name as string,
   363|          vcpu: args.vcpu as number,
   364|          memoryMb: args.memory_mb as number,
   365|          diskGb: args.disk_gb as number,
   366|        });
   367|        return `Sandbox created: ${info.id} (${info.vcpu} vCPU, ${info.memoryMb}MB RAM)`;
   368|      },
   369|    },
   370|    {
   371|      name: "delete_sandbox",
   372|      description: "Delete a sandbox. Note: sandbox deletion is currently disabled by the Conway API.",
   373|      category: "conway",
   374|      riskLevel: "dangerous",
   375|      parameters: {
   376|        type: "object",
   377|        properties: {
   378|          sandbox_id: {
   379|            type: "string",
   380|            description: "ID of sandbox to delete",
   381|          },
   382|        },
   383|        required: ["sandbox_id"],
   384|      },
   385|      execute: async () => {
   386|        return "Sandbox deletion is disabled. Sandboxes are prepaid and non-refundable.";
   387|      },
   388|    },
   389|    {
   390|      name: "list_sandboxes",
   391|      description: "List all your sandboxes.",
   392|      category: "conway",
   393|      riskLevel: "safe",
   394|      parameters: { type: "object", properties: {} },
   395|      execute: async (_args, ctx) => {
   396|        const sandboxes = await ctx.conway.listSandboxes();
   397|        if (sandboxes.length === 0) return "No sandboxes found.";
   398|        return sandboxes
   399|          .map(
   400|            (s) =>
   401|              `${s.id} [${s.status}] ${s.vcpu}vCPU/${s.memoryMb}MB ${s.region}`,
   402|          )
   403|          .join("\n");
   404|      },
   405|    },
   406|
   407|    // ‚îÄ‚îÄ Self-Modification Tools ‚îÄ‚îÄ
   408|    {
   409|      name: "edit_own_file",
   410|      description:
   411|        "Edit a file in your own codebase. Changes are audited, rate-limited, and safety-checked. Some files are protected.",
   412|      category: "self_mod",
   413|      riskLevel: "dangerous",
   414|      parameters: {
   415|        type: "object",
   416|        properties: {
   417|          path: { type: "string", description: "File path to edit" },
   418|          content: { type: "string", description: "New file content" },
   419|          description: {
   420|            type: "string",
   421|            description: "Why you are making this change",
   422|          },
   423|        },
   424|        required: ["path", "content", "description"],
   425|      },
   426|      execute: async (args, ctx) => {
   427|        const { editFile, validateModification } =
   428|          await import("../self-mod/code.js");
   429|        const filePath = args.path as string;
   430|        const content = args.content as string;
   431|
   432|        // Pre-validate before attempting
   433|        const validation = validateModification(
   434|          ctx.db,
   435|          filePath,
   436|          content.length,
   437|        );
   438|        if (!validation.allowed) {
   439|          return `BLOCKED: ${validation.reason}\nChecks: ${validation.checks.map((c) => `${c.name}: ${c.passed ? "PASS" : "FAIL"} (${c.detail})`).join(", ")}`;
   440|        }
   441|
   442|        const result = await editFile(
   443|          ctx.conway,
   444|          ctx.db,
   445|          filePath,
   446|          content,
   447|          args.description as string,
   448|        );
   449|
   450|        if (!result.success) {
   451|          return result.error || "Unknown error during file edit";
   452|        }
   453|
   454|        const msg = `File edited: ${filePath} (audited + git-committed)`;
   455|        return result.error ? `${msg}\nWarning: ${result.error}` : msg;
   456|      },
   457|    },
   458|    {
   459|      name: "revert_last_edit",
   460|      description:
   461|        "Revert the last self-modification. Uses git to undo the most recent code change and rebuild.",
   462|      category: "self_mod",
   463|      riskLevel: "caution",
   464|      parameters: { type: "object", properties: {} },
   465|      execute: async (_args, ctx) => {
   466|        const repoRoot = process.cwd();
   467|
   468|        // Show what we're reverting
   469|        const lastCommit = await ctx.conway.exec(
   470|          `cd '${repoRoot}' && git log -1 --oneline`,
   471|          10_000,
   472|        );
   473|
   474|        // Revert
   475|        const result = await ctx.conway.exec(
   476|          `cd '${repoRoot}' && git revert HEAD --no-edit`,
   477|          30_000,
   478|        );
   479|        if (result.exitCode !== 0) {
   480|          return `Revert failed: ${result.stderr}`;
   481|        }
   482|
   483|        // Rebuild
   484|        const build = await ctx.conway.exec(
   485|          `cd '${repoRoot}' && npm run build`,
   486|          60_000,
   487|        );
   488|
   489|        // Audit log
   490|        const { logModification } = await import("../self-mod/audit-log.js");
   491|        logModification(ctx.db, "code_revert", `Reverted: ${lastCommit.stdout.trim()}`, {
   492|          reversible: true,
   493|        });
   494|
   495|        return `Reverted: ${lastCommit.stdout.trim()}. ${build.exitCode === 0 ? "Rebuild succeeded." : "Rebuild failed: " + build.stderr}`;
   496|      },
   497|    },
   498|    {
   499|      name: "reset_to_upstream",
   500|      description:
