{"content": "     1|/**
     2| * Skills Registry
     3| *
     4| * Install skills from remote sources:
     5| * - Git repos: git clone <url> ~/.automaton/skills/<name>
     6| * - URLs: fetch a SKILL.md from any URL
     7| * - Self-created: the automaton writes its own SKILL.md files
     8| *
     9| * All shell commands use execFileSync with argument arrays to prevent injection.
    10| * Directory operations use fs.* to avoid shell interpolation entirely.
    11| */
    12|
    13|import { execFileSync } from "child_process";
    14|import fs from "fs";
    15|import path from "path";
    16|import * as yaml from "yaml";
    17|import type {
    18|  Skill,
    19|  SkillSource,
    20|  AutomatonDatabase,
    21|  ConwayClient,
    22|} from "../types.js";
    23|import { parseSkillMd } from "./format.js";
    24|
    25|// Validation patterns to prevent injection via path/URL arguments
    26|const SKILL_NAME_RE = /^[a-zA-Z0-9-]+$/;
    27|const SAFE_URL_RE = /^https?:\/\/[^\s;|&$`(){}<>]+$/;
    28|
    29|// Size limits for skill content
    30|const MAX_DESCRIPTION_LENGTH = 500;
    31|const MAX_INSTRUCTIONS_LENGTH = 10_000;
    32|
    33|/**
    34| * Validate that a skill path does not escape the skills directory.
    35| * Prevents path traversal attacks via crafted skill names.
    36| */
    37|function validateSkillPath(skillsDir: string, name: string): string {
    38|  const resolved = path.resolve(skillsDir, name);
    39|  if (!resolved.startsWith(path.resolve(skillsDir) + path.sep)) {
    40|    throw new Error(`Skill path traversal detected: ${name}`);
