  2840|        // Dedup: reject if a similar active goal already exists
  2841|        const activeGoals = getActiveGoals(ctx.db.raw);
  2842|        const titleLower = title.toLowerCase();
  2843|        const duplicate = activeGoals.find(
  2844|          (g) =>
  2845|            g.title.toLowerCase() === titleLower ||
  2846|            g.title.toLowerCase().includes(titleLower) ||
  2847|            titleLower.includes(g.title.toLowerCase()),
