      execute: async (args, ctx) => {
        const prompt = args.prompt as string;
        const width = (args.width as number) || 768;
        const height = (args.height as number) || 768;
        const seed = (args.seed as number) || -1;
        const model = (args.model as string) || "sana";

        // Build Pollinations URL
        const encodedPrompt = encodeURIComponent(prompt);
        let url = `https://image.pollinations.ai/prompt/${encodedPrompt}?width=${width}&height=${height}&seed=${seed}&model=${model}`;

        // Generate filename
        const timestamp = Date.now();
        const safeName = prompt.slice(0, 30).replace(/[^a-zA-Z0-9]/g, "_");
        const outputPath = `/tmp/image_${timestamp}_${safeName}.png`;

        // Download image via curl
        const result = await ctx.conway.exec(
          `curl -s "${url}" -o "${outputPath}" --max-time 90`,
          95_000,
        );

        if (result.exitCode !== 0) {
          return `Image generation failed: ${result.stderr}`;
        }

        // Verify file is valid
        const check = await ctx.conway.exec(
          `file "${outputPath}" && ls -lh "${outputPath}"`,
          10_000,
