          return `Image generation failed. Server responded: ${cat.stdout.slice(0, 500)}`;
        }

        return `Image generated successfully:\nPrompt: "${prompt}"\nModel: ${model}\nSize: ${width}x${height}\nSeed: ${seed}\nSaved to: ${outputPath}\n${check.stdout.trim()}`;
      },
    },

