   356|    return { shouldWake: false };
   357|  },
   358|
   359|  // === Phase 3.1: Child Health Check ===
   360|  check_child_health: async (_ctx: TickContext, taskCtx: HeartbeatLegacyContext) => {
   361|    try {
   362|      const { ChildLifecycle } = await import("../replication/lifecycle.js");
   363|      const { ChildHealthMonitor } = await import("../replication/health.js");
   364|      const lifecycle = new ChildLifecycle(taskCtx.db.raw);
   365|      const monitor = new ChildHealthMonitor(taskCtx.db.raw, taskCtx.conway, lifecycle);
   366|      const results = await monitor.checkAllChildren();
   367|
   368|      const unhealthy = results.filter((r) => !r.healthy);
   369|      if (unhealthy.length > 0) {
   370|        for (const r of unhealthy) {
   371|          logger.warn(`Child ${r.childId} unhealthy: ${r.issues.join(", ")}`);
   372|        }
   373|        return {
   374|          shouldWake: true,
   375|          message: `${unhealthy.length} child(ren) unhealthy: ${unhealthy.map((r) => r.childId.slice(0, 8)).join(", ")}`,
   376|        };
   377|      }
   378|    } catch (error) {
   379|      logger.error("check_child_health failed", error instanceof Error ? error : undefined);
   380|    }
   381|    return { shouldWake: false };
   382|  },
   383|
   384|  // === Phase 3.1: Prune Dead Children ===
   385|  prune_dead_children: async (_ctx: TickContext, taskCtx: HeartbeatLegacyContext) => {
   386|    try {
   387|      const { ChildLifecycle } = await import("../replication/lifecycle.js");
   388|      const { SandboxCleanup } = await import("../replication/cleanup.js");
   389|      const { pruneDeadChildren } = await import("../replication/lineage.js");
   390|      const lifecycle = new ChildLifecycle(taskCtx.db.raw);
   391|      const cleanup = new SandboxCleanup(taskCtx.conway, lifecycle, taskCtx.db.raw);
   392|      const pruned = await pruneDeadChildren(taskCtx.db, cleanup);
   393|      if (pruned > 0) {
   394|        logger.info(`Pruned ${pruned} dead children`);
   395|      }
   396|    } catch (error) {
   397|      logger.error("prune_dead_children failed", error instanceof Error ? error : undefined);
   398|    }
   399|    return { shouldWake: false };
   400|  },
   401|
   402|  health_check: async (_ctx: TickContext, taskCtx: HeartbeatLegacyContext) => {
   403|    // Check that the sandbox is healthy
   404|    try {
   405|      const result = await taskCtx.conway.exec("echo alive", 5000);
   406|      if (result.exitCode !== 0) {
   407|        // Only wake on first failure, not repeated failures
   408|        const prevStatus = taskCtx.db.getKV("health_check_status");
   409|        if (prevStatus !== "failing") {
   410|          taskCtx.db.setKV("health_check_status", "failing");
   411|          return {
   412|            shouldWake: true,
   413|            message: "Health check failed: sandbox exec returned non-zero",
   414|          };
   415|        }
   416|        return { shouldWake: false };
   417|      }
   418|    } catch (err: any) {
   419|      // Only wake on first failure, not repeated failures
   420|      const prevStatus = taskCtx.db.getKV("health_check_status");
   421|      if (prevStatus !== "failing") {
   422|        taskCtx.db.setKV("health_check_status", "failing");
   423|        return {
   424|          shouldWake: true,
   425|          message: `Health check failed: ${err.message}`,
   426|        };
   427|      }
   428|      return { shouldWake: false };
   429|    }
   430|
   431|    // Health check passed ‚Äî clear failure state
   432|    taskCtx.db.setKV("health_check_status", "ok");
   433|    taskCtx.db.setKV("last_health_check", new Date().toISOString());
   434|    return { shouldWake: false };
   435|  },
   436|
   437|  // === Phase 4.1: Metrics Reporting ===
   438|  report_metrics: async (ctx: TickContext, taskCtx: HeartbeatLegacyContext) => {
   439|    try {
   440|      const metrics = getMetrics();
   441|      const alerts = getAlertEngine();
   442|
   443|      // Update gauges from tick context
   444|      metrics.gauge("balance_cents", ctx.creditBalance);
   445|      metrics.gauge("survival_tier", tierToInt(ctx.survivalTier));
   446|
   447|      // Evaluate alerts
   448|      const firedAlerts = alerts.evaluate(metrics);
