   450|      // Save snapshot to DB
   451|      metricsInsertSnapshot(taskCtx.db.raw, {
   452|        id: ulid(),
   453|        snapshotAt: new Date().toISOString(),
   454|        metricsJson: JSON.stringify(metrics.getAll()),
   455|        alertsJson: JSON.stringify(firedAlerts),
   456|        createdAt: new Date().toISOString(),
   457|      });
   458|
   459|      // Prune old snapshots (keep 7 days)
   460|      metricsPruneOld(taskCtx.db.raw, 7);
   461|
   462|      // Log alerts
   463|      for (const alert of firedAlerts) {
   464|        logger.warn(`Alert: ${alert.rule} - ${alert.message}`, { alert });
