   476|
   477|  colony_health_check: async (_ctx: TickContext, taskCtx: HeartbeatLegacyContext) => {
   478|    if (!shouldRunAtInterval(taskCtx, "colony_health_check", COLONY_TASK_INTERVALS_MS.colony_health_check)) {
   479|      return { shouldWake: false };
   480|    }
