   482|    try {
   483|      const monitor = await createHealthMonitor(taskCtx);
   484|      const report = await monitor.checkAll();
   485|      const actions = await monitor.autoHeal(report);
   486|
   487|      taskCtx.db.setKV("last_colony_health_report", JSON.stringify(report));
   488|      taskCtx.db.setKV("last_colony_heal_actions", JSON.stringify({
   489|        timestamp: new Date().toISOString(),
   490|        actions,
