     2| * Alert Engine
     3| *
     4| * Evaluates alert rules against metric snapshots.
     5| * Tracks cooldowns per rule to avoid alert storms.
     6| * Never throws ‚Äî evaluates all rules and collects errors silently.
     7| */
     8|
     9|import type { AlertRule, AlertEvent, AlertSeverity, MetricSnapshot } from "../types.js";
    10|
    11|export function createDefaultAlertRules(): AlertRule[] {
    12|  return [
    13|    {
    14|      name: "balance_below_reserve",
    15|      severity: "critical",
    16|      message: "Balance is below minimum reserve (1000 cents)",
    17|      cooldownMs: 5 * 60 * 1000, // 5 min
    18|      condition: (metrics: MetricSnapshot) => {
    19|        const balance = metrics.gauges.get("balance_cents") ?? Infinity;
    20|        return balance < 1000;
    21|      },
    22|    },
    23|    {
    24|      name: "heartbeat_high_failure_rate",
    25|      severity: "warning",
    26|      message: "Heartbeat task failure rate exceeds 20%",
    27|      cooldownMs: 15 * 60 * 1000, // 15 min
    28|      condition: (metrics: MetricSnapshot) => {
    29|        const failures = metrics.counters.get("heartbeat_task_failures_total") ?? 0;
    30|        const successes = metrics.counters.get("heartbeat_task_successes_total") ?? 0;
    31|        const total = failures + successes;
    32|        if (total === 0) return false;
    33|        return failures / total > 0.2;
    34|      },
    35|    },
    36|    {
    37|      name: "policy_high_deny_rate",
    38|      severity: "warning",
    39|      message: "Policy deny rate exceeds 50%",
    40|      cooldownMs: 15 * 60 * 1000, // 15 min
    41|      condition: (metrics: MetricSnapshot) => {
    42|        const denies = metrics.counters.get("policy_denies_total") ?? 0;
    43|        const total = metrics.counters.get("policy_decisions_total") ?? 0;
    44|        if (total < 10) return false; // Need minimum sample size
    45|        return denies / total > 0.5;
    46|      },
    47|    },
    48|    {
    49|      name: "context_near_capacity",
    50|      severity: "warning",
    51|      message: "Context token usage above 90% of budget",
    52|      cooldownMs: 10 * 60 * 1000, // 10 min
    53|      condition: (metrics: MetricSnapshot) => {
    54|        const tokens = metrics.gauges.get("context_tokens_total") ?? 0;
    55|        // 100k default budget
    56|        return tokens > 90_000;
    57|      },
    58|    },
    59|    {
    60|      name: "inference_budget_warning",
    61|      severity: "warning",
    62|      message: "Daily inference cost exceeding 80% of cap",
    63|      cooldownMs: 30 * 60 * 1000, // 30 min
    64|      condition: (metrics: MetricSnapshot) => {
    65|        const cost = metrics.counters.get("inference_cost_cents") ?? 0;
    66|        // 500 cents ($5) daily default cap
    67|        return cost > 400;
    68|      },
    69|    },
    70|    {
    71|      name: "child_unhealthy_extended",
    72|      severity: "warning",
    73|      message: "Child has been unhealthy for extended period",
    74|      cooldownMs: 30 * 60 * 1000, // 30 min
    75|      condition: (metrics: MetricSnapshot) => {
    76|        const unhealthy = metrics.gauges.get("unhealthy_child_count") ?? 0;
    77|        return unhealthy > 0;
    78|      },
    79|    },
    80|    {
    81|      name: "zero_turns_last_hour",
    82|      severity: "critical",
    83|      message: "No successful turns in the last hour",
    84|      cooldownMs: 60 * 60 * 1000, // 60 min
    85|      condition: (metrics: MetricSnapshot) => {
    86|        const turnsLastHour = metrics.gauges.get("turns_last_hour") ?? -1;
    87|        // Use windowed gauge if available; fall back to cumulative counter only
    88|        // when the gauge hasn't been set yet (-1 sentinel).
    89|        if (turnsLastHour >= 0) return turnsLastHour === 0;
    90|        const turnsTotal = metrics.counters.get("turns_total") ?? -1;
    91|        // If turns_total was never set, assume we just started ‚Äî don't alert
    92|        if (turnsTotal < 0) return false;
    93|        return turnsTotal === 0;
    94|      },
    95|    },
    96|  ];
    97|}
    98|
    99|export class AlertEngine {
   100|  private rules: AlertRule[];
   101|  private lastFired = new Map<string, number>();
   102|  private activeAlerts: AlertEvent[] = [];
   103|
   104|  constructor(rules?: AlertRule[]) {
   105|    this.rules = rules ?? createDefaultAlertRules();
   106|  }
   107|
   108|  addRule(rule: AlertRule): void {
   109|    try {
   110|      this.rules.push(rule);
   111|    } catch { /* never throw */ }
   112|  }
   113|
   114|  evaluate(metrics: MetricsCollector | MetricSnapshot): AlertEvent[] {
   115|    const snapshot: MetricSnapshot = "getSnapshot" in metrics
   116|      ? (metrics as any).getSnapshot()
   117|      : metrics as MetricSnapshot;
   118|
   119|    const now = Date.now();
   120|    const fired: AlertEvent[] = [];
   121|
   122|    for (const rule of this.rules) {
   123|      try {
   124|        const lastTime = this.lastFired.get(rule.name) ?? 0;
   125|        if (now - lastTime < rule.cooldownMs) continue;
   126|
   127|        if (rule.condition(snapshot)) {
   128|          const event: AlertEvent = {
   129|            rule: rule.name,
   130|            severity: rule.severity,
   131|            message: rule.message,
   132|            firedAt: new Date().toISOString(),
   133|            metricValues: this.extractMetricValues(snapshot),
   134|          };
   135|          fired.push(event);
   136|          this.lastFired.set(rule.name, now);
   137|
   138|          // Update active alerts (replace existing for same rule)
   139|          this.activeAlerts = this.activeAlerts.filter((a) => a.rule !== rule.name);
   140|          this.activeAlerts.push(event);
   141|        }
   142|      } catch { /* never throw ‚Äî skip this rule */ }
   143|    }
   144|
   145|    return fired;
   146|  }
   147|
   148|  getActiveAlerts(): AlertEvent[] {
   149|    return [...this.activeAlerts];
   150|  }
   151|
   152|  clearAlert(ruleName: string): void {
   153|    try {
   154|      this.activeAlerts = this.activeAlerts.filter((a) => a.rule !== ruleName);
   155|      this.lastFired.delete(ruleName);
   156|    } catch { /* never throw */ }
   157|  }
   158|
   159|  private extractMetricValues(snapshot: MetricSnapshot): Record<string, number> {
   160|    const values: Record<string, number> = {};
   161|    try {
   162|      for (const [key, value] of snapshot.gauges) {
   163|        values[key] = value;
   164|      }
   165|      for (const [key, value] of snapshot.counters) {
   166|        values[key] = value;
   167|      }
   168|    } catch { /* never throw */ }
   169|    return values;
   170|  }
   171|}
   172|
   173|// Type-import for evaluate() overload compatibility
   174|import type { MetricsCollector } from "./metrics.js";
   175|", "total_lines": 174, "file_size": 5796, "truncated": false, "is_binary": false, "is_image": false}

{"content": "     1|/**
     2| * Heartbeat Daemon
     3| *
     4| * Runs periodic tasks on cron schedules inside the same Node.js process.
     5| * The heartbeat runs even when the agent is sleeping.
     6| * It IS the automaton's pulse. When it stops, the automaton is dead.
     7| *
     8| * Phase 1.1: Replaced fragile setInterval with DurableScheduler.
     9| * - No setInterval remains; uses recursive setTimeout for overlap protection
    10| * - Tick frequency derived from config.defaultIntervalMs, not log level
    11| * - lowComputeMultiplier applied to non-essential tasks via scheduler
    12| */
    13|
    14|import type {
    15|  AutomatonConfig,
    16|  AutomatonDatabase,
    17|  ConwayClient,
    18|  AutomatonIdentity,
    19|  HeartbeatConfig,
    20|  HeartbeatTaskFn,
    21|  HeartbeatLegacyContext,
    22|  SocialClientInterface,
    23|} from "../types.js";
    24|import { BUILTIN_TASKS } from "./tasks.js";
    25|import { DurableScheduler } from "./scheduler.js";
    26|import { upsertHeartbeatSchedule } from "../state/database.js";
    27|import type BetterSqlite3 from "better-sqlite3";
    28|import { createLogger } from "../observability/logger.js";
    29|
    30|const logger = createLogger("heartbeat");
    31|
    32|type DatabaseType = BetterSqlite3.Database;
    33|
    34|export interface HeartbeatDaemonOptions {
    35|  identity: AutomatonIdentity;
    36|  config: AutomatonConfig;
    37|  heartbeatConfig: HeartbeatConfig;
    38|  db: AutomatonDatabase;
    39|  rawDb: DatabaseType;
    40|  conway: ConwayClient;
    41|  social?: SocialClientInterface;
    42|  onWakeRequest?: (reason: string) => void;
    43|}
    44|
    45|export interface HeartbeatDaemon {
    46|  start(): void;
    47|  stop(): void;
    48|  isRunning(): boolean;
    49|  forceRun(taskName: string): Promise<void>;
    50|}
    51|
    52|/**
    53| * Create and return the heartbeat daemon.
    54| *
    55| * Uses DurableScheduler backed by the DB instead of setInterval.
    56| * Tick interval comes from heartbeatConfig.defaultIntervalMs.
    57| */
    58|export function createHeartbeatDaemon(
    59|  options: HeartbeatDaemonOptions,
    60|): HeartbeatDaemon {
    61|  const { identity, config, heartbeatConfig, db, rawDb, conway, social, onWakeRequest } = options;
    62|  let timeoutId: ReturnType<typeof setTimeout> | null = null;
    63|  let running = false;
    64|
    65|  const legacyContext: HeartbeatLegacyContext = {
    66|    identity,
    67|    config,
    68|    db,
    69|    conway,
    70|    social,
    71|  };
    72|
    73|  // Build task map from BUILTIN_TASKS
    74|  const taskMap = new Map<string, HeartbeatTaskFn>();
    75|  for (const [name, fn] of Object.entries(BUILTIN_TASKS)) {
    76|    taskMap.set(name, fn);
    77|  }
    78|
    79|  // Seed heartbeat_schedule from config entries if not already present
    80|  for (const entry of heartbeatConfig.entries) {
    81|    upsertHeartbeatSchedule(rawDb, {
    82|      taskName: entry.name,
    83|      cronExpression: entry.schedule,
    84|      intervalMs: null,
    85|      enabled: entry.enabled ? 1 : 0,
    86|      priority: 0,
    87|      timeoutMs: 30_000,
    88|      maxRetries: 1,
    89|      tierMinimum: "dead",
    90|      lastRunAt: entry.lastRun ?? null,
    91|      nextRunAt: entry.nextRun ?? null,
    92|      lastResult: null,
    93|      lastError: null,
    94|      runCount: 0,
    95|      failCount: 0,
    96|      leaseOwner: null,
    97|      leaseExpiresAt: null,
    98|    });
    99|  }
   100|
   101|  const scheduler = new DurableScheduler(
   102|    rawDb,
   103|    heartbeatConfig,
   104|    taskMap,
   105|    legacyContext,
   106|    onWakeRequest,
   107|  );
   108|
   109|  // Tick interval from config (not log level)
   110|  const tickMs = heartbeatConfig.defaultIntervalMs ?? 60_000;
   111|
   112|  /**
   113|   * Recursive setTimeout loop for overlap protection.
   114|   * Each tick must complete before the next is scheduled.
   115|   */
   116|  function scheduleTick(): void {
   117|    if (!running) return;
   118|    timeoutId = setTimeout(async () => {
   119|      try {
   120|        await scheduler.tick();
   121|      } catch (err: any) {
   122|        logger.error("Tick failed", err instanceof Error ? err : undefined);
   123|      }
   124|      scheduleTick();
   125|    }, tickMs);
   126|  }
   127|
   128|  // ‚îÄ‚îÄ‚îÄ Public API ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
   129|
   130|  const start = (): void => {
   131|    if (running) return;
   132|    running = true;
   133|
   134|    // Run first tick immediately
   135|    scheduler.tick().catch((err) => {
   136|      logger.error("First tick failed", err instanceof Error ? err : undefined);
   137|    });
   138|
   139|    // Schedule subsequent ticks
   140|    scheduleTick();
   141|
   142|    logger.info(`Daemon started. Tick interval: ${tickMs / 1000}s (from config)`);
   143|  };
   144|
   145|  const stop = (): void => {
   146|    if (!running) return;
   147|    running = false;
   148|    if (timeoutId) {
   149|      clearTimeout(timeoutId);
   150|      timeoutId = null;
   151|    }
   152|    logger.info("Daemon stopped.");
   153|  };
   154|
   155|  const isRunning = (): boolean => running;
   156|
   157|  const forceRun = async (taskName: string): Promise<void> => {
   158|    const context = await import("./tick-context.js").then((m) =>
   159|      m.buildTickContext(rawDb, conway, heartbeatConfig, identity.address, identity.chainType),
   160|    );
   161|    await scheduler.executeTask(taskName, context);
   162|  };
   163|
   164|  return { start, stop, isRunning, forceRun };
   165|}
   166|", "total_lines": 165, "file_size": 4679, "truncated": false, "is_binary": false, "is_image": false}

