    // ── Owner Alerting ──
    {
      name: "alert_owner",
      description:
        "Send an urgent alert directly to the owner's Telegram. Use ONLY for critical situations: credits running out, agent about to die, or other emergencies requiring immediate human attention. Be concise — this sends a Telegram message.",
      category: "vm",
      riskLevel: "caution",
      parameters: {
        type: "object",
        properties: {
          message: {
            type: "string",
            description: "The alert message to send to the owner",
          },
          priority: {
            type: "string",
            enum: ["low", "normal", "high", "critical"],
            description: "Alert priority level (default: normal)",
          },
        },
        required: ["message"],
      },
      execute: async (args, ctx) => {
        const message = args.message as string;
        const priority = (args.priority as string) || "normal";

        // Get bot token from hermes config
        let botToken = "";
        try {
          const { readFileSync } = await import("fs");
          const configPath = `${process.env.HOME || "/root"}/.hermes/dotfiles/config/config.yaml`;
          const configContent = readFileSync(configPath, "utf-8");
          const match = configContent.match(/bot_token:\s*([A-Za-z0-9._-]+)/);
          if (match) botToken = match[1];
        } catch {
          return "ERROR: Could not read Telegram bot token from config";
        }

        if (!botToken) return "ERROR: Telegram bot token not found in config";

        const ownerChatId = "8177017832";
        const emoji = priority === "critical" ? "🚨" : priority === "high" ? "⚠️" : "ℹ️";
        const fullMessage = `${emoji} *Automaton Alert*\n\n${message}`;

        const payload = JSON.stringify({
          chat_id: ownerChatId,
          text: fullMessage,
          parse_mode: "Markdown",
        });

        const result = await ctx.conway.exec(
          `curl -s -X POST "https://api.telegram.org/bot${botToken}/sendMessage" -H "Content-Type: application/json" -d '${payload}'`,
          15_000,
        );

        if (result.exitCode !== 0) {
          return `Alert failed: ${result.stderr}`;
        }

        try {
          const resp = JSON.parse(result.stdout);
          if (resp.ok) {
            return `Alert sent to owner via Telegram (priority: ${priority})`;
          } else {
            return `Telegram API error: ${resp.description || JSON.stringify(resp)}`;
          }
        } catch {
          return `Alert sent (response: ${result.stdout.slice(0, 100)})`;
        }
      },
    },

